guidance.verification:
# Verifica stato account Administrator su tutti i DC
Get-ADDomainController -Filter * | ForEach-Object {
    $u = Get-ADUser -Identity 500 -Server $_.Name -Properties Enabled, SamAccountName
    [PSCustomObject]@{ DC=$_.Name; Nome=$u.SamAccountName; Abilitato=$u.Enabled }
}

# Verifica via GPO applicata
gpresult /r /scope:computer | findstr -i 'administrator'

# Verifica stato Guest su tutto il dominio
Get-ADDomainController -Filter * | ForEach-Object {
    $g = Get-ADUser -Identity 'Guest' -Server $_.Name -Properties Enabled
    [PSCustomObject]@{ DC=$_.Name; Abilitato=$g.Enabled }
}

items.command_full:
# Audit completo membership
Get-ADGroupMember -Identity 'Domain Admins' -Recursive | ForEach-Object {
    $u = Get-ADObject $_.distinguishedName -Properties LastLogonDate, PasswordLastSet, Enabled
    [PSCustomObject]@{
        Nome           = $_.Name
        Tipo           = $_.objectClass
        Abilitato      = $u.Enabled
        UltimoLogon    = $u.LastLogonDate
        UltimaPwd      = $u.PasswordLastSet
    }
} | Format-Table -AutoSize

# Rimuovi account non necessari
Remove-ADGroupMember -Identity 'Domain Admins' -Members 'utente01' -Confirm:$false

# Audit entrambi i gruppi
foreach ($group in @('Enterprise Admins','Schema Admins')) {
    $members = Get-ADGroupMember -Identity $group -Recursive
    Write-Host "=== $group ==="
    if ($members.Count -eq 0) { Write-Host 'VUOTO (corretto)' }
    else { $members | Select Name, SamAccountName, objectClass | Format-Table }
}

# Rimuovi tutti i membri
Get-ADGroupMember 'Enterprise Admins' | ForEach-Object {
    Remove-ADGroupMember -Identity 'Enterprise Admins' -Members $_ -Confirm:$false
}

guidance.verification:
# Sistemi senza password LAPS (non compliance)
Get-ADComputer -Filter * -SearchBase 'OU=Workstations,DC=corp,DC=local' |
    ForEach-Object {
        $pwd = Get-AdmPwdPassword -ComputerName $_.Name
        if (-not $pwd.Password) { Write-Warning "LAPS mancante: $($_.Name)" }
    }

items.command_full:
# Imposta via registry (livello 5 = NTLMv2 only, rifiuta LM e NTLMv1)
Set-ItemProperty -Path 'HKLM:\SYSTEM\CurrentControlSet\Control\Lsa' `
    -Name 'LmCompatibilityLevel' -Value 5 -Type DWord

# Verifica su tutti i DC
$dcs = Get-ADDomainController -Filter * | Select -Exp HostName
Invoke-Command -ComputerName $dcs -ScriptBlock {
    $val = (Get-ItemProperty 'HKLM:\SYSTEM\CurrentControlSet\Control\Lsa' -Name LmCompatibilityLevel).LmCompatibilityLevel
    [PSCustomObject]@{ Server=$env:COMPUTERNAME; LmCompatLevel=$val; Corretto=($val -ge 5) }
}

guidance.verification:
# Verifica su tutti i sistemi del dominio
Get-ADComputer -Filter * | ForEach-Object {
    $val = Invoke-Command -ComputerName $_.Name -ScriptBlock {
        (Get-ItemProperty 'HKLM:\SYSTEM\CurrentControlSet\Control\Lsa').LmCompatibilityLevel
    } -ErrorAction SilentlyContinue
    [PSCustomObject]@{ Computer=$_.Name; LmCompat=$val; OK=($val -ge 5) }
} | Where-Object { -not $_.OK }

# Verifica GPO applicate al DC
Invoke-Command -ComputerName 'DC01' -ScriptBlock {
    gpresult /r /scope:computer 2>&1
} | Select-String 'Applied Group Policy'

# Verifica impostazioni su tutti i DC
Get-ADDomainController -Filter * | ForEach-Object {
    $signing = Invoke-Command -ComputerName $_.Name -ScriptBlock {
        (Get-ItemProperty 'HKLM:\SYSTEM\CurrentControlSet\Services\NTDS\Parameters').LDAPServerIntegrity
    }
    [PSCustomObject]@{ DC=$_.Name; LDAPSigning=$signing; Corretto=($signing -eq 2) }
}

items.command_full:
# Audit patch su tutti i DC
$dcs = Get-ADDomainController -Filter * | Select -Exp HostName
Invoke-Command -ComputerName $dcs -ScriptBlock {
    $lastPatch = (Get-HotFix | Sort-Object InstalledOn -Descending | Select -First 1)
    $pending   = (New-Object -ComObject Microsoft.Update.Session).CreateUpdateSearcher().Search('IsInstalled=0 AND Type=\'Software\'').Updates.Count
    [PSCustomObject]@{
        DC            = $env:COMPUTERNAME
        UltimaPath    = $lastPatch.InstalledOn
        PatchMancanti = $pending
    }
}
